    private List<ErrorInfo> erroresSintacticos = new ArrayList<>();

    public List<ErrorInfo> getErroresSintacticos() {
        return erroresSintacticos;
    }

    public void syntax_error(Symbol s) {
        // Construir lista de tokens esperados traducidos al español
        List<Integer> ids = expected_token_ids();
        List<String> esperados = new ArrayList<>();
        for (Integer id : ids) {
            esperados.add(traductor(symbl_name_from_id(id)));
        }

        String encontrado = (s != null && s.value != null)
            ? s.value.toString()
            : traductor(symbl_name_from_id(s != null ? s.sym : 0));

        int linea   = s != null ? s.left  : 0;
        int columna = s != null ? s.right : 0;

        String mensaje = esperados.isEmpty()
            ? "Token inesperado '" + encontrado + "'"
            : "Se esperaba: " + String.join(", ", esperados)
              + ". Pero se encontró: '" + encontrado + "'";

        erroresSintacticos.add(new ErrorInfo(TipoError.SINTACTICO, mensaje, linea, columna));
    }

    public void report_error(String message, Object info) {
        // Los errores ya se gestionan en syntax_error; evitar mensajes duplicados
    }

    /** Traduce el nombre interno del token a una descripción legible en español. */
    private String traductor(String token) {
        if (token == null) return "desconocido";
        switch (token) {
            // --- Componentes UI ---
            case "SECTION":           return "SECTION";
            case "TABLE":             return "TABLE";
            case "TEXT":              return "TEXT";
            case "OPEN_QUESTION":     return "OPEN_QUESTION";
            case "DROP_QUESTION":     return "DROP_QUESTION";
            case "SELECT_QUESTION":   return "SELECT_QUESTION";
            case "MULTIPLE_QUESTION": return "MULTIPLE_QUESTION";
            // --- Atributos ---
            case "WIDTH":             return "width";
            case "HEIGHT":            return "height";
            case "POINT_X":           return "pointX";
            case "POINT_Y":           return "pointY";
            case "ORIENTATION":       return "orientation";
            case "ELEMENTS":          return "elements";
            case "STYLES":            return "styles";
            case "COLOR_ATTR":        return "color";
            case "BACKGROUND_COLOR":  return "background color";
            case "FONT_FAMILY":       return "font family";
            case "TEXT_SIZE":         return "text size";
            case "BORDER":            return "border";
            case "CONTENT":           return "content";
            case "LABEL":             return "label";
            case "OPTIONS":           return "options";
            case "CORRECT":           return "correct";
            // --- Tipos ---
            case "TYPE_NUMBER":       return "number";
            case "TYPE_STRING":       return "string";
            case "TYPE_SPECIAL":      return "special";
            // --- Orientación ---
            case "VERTICAL":          return "VERTICAL";
            case "HORIZONTAL":        return "HORIZONTAL";
            case "MONO":              return "MONO";
            // --- Control ---
            case "IF":                return "IF";
            case "ELSE":              return "ELSE";
            case "WHILE":             return "WHILE";
            case "DO":                return "DO";
            case "FOR":               return "FOR";
            case "IN":                return "in";
            // --- Funciones especiales ---
            case "FUNC_POKEMON":      return "who_is_that_pokemon";
            case "DRAW":              return "draw";
            // --- Símbolos estructurales ---
            case "CORCHETE_IZQ":      return "'['";
            case "CORCHETE_DER":      return "']'";
            case "LLAVE_IZQ":         return "'{'";
            case "LLAVE_DER":         return "'}'";
            case "PAREN_IZQ":         return "'('";
            case "PAREN_DER":         return "')'";
            case "COMA":              return "','";
            case "DOS_PUNTOS":        return "':'";
            case "ASIGNACION":        return "'='";
            case "PUNTO":             return "'.'";
            case "COMODIN":           return "'?'";
            // --- Operadores aritméticos ---
            case "MAS":               return "'+'";
            case "MENOS":             return "'-'";
            case "POR":               return "'*'";
            case "DIV":               return "'/'";
            case "POTENCIA":          return "'^'";
            case "MODULO":            return "'%'";
            // --- Operadores relacionales ---
            case "MAYOR":             return "'>'";
            case "MENOR":             return "'<'";
            case "MAYOR_IGUAL":       return "'>='";
            case "MENOR_IGUAL":       return "'<='";
            case "IGUALDAD":          return "'=='";
            case "DIFERENTE":         return "'!!'";
            // --- Operadores lógicos ---
            case "OR":                return "'||'";
            case "AND":               return "'&&'";
            case "NOT":               return "'!'";
            // --- Literales e identificadores ---
            case "ID":                return "identificador";
            case "NUMBER_LITERAL":    return "número";
            case "INICIO_CADENA":     return "'\"' (inicio de cadena)";
            case "FIN_CADENA":        return "'\"' (fin de cadena)";
            case "CONTENIDO_CADENA":  return "contenido de cadena";
            // --- Emojis ---
            case "EMOJI_SMILE":       return "emoji @[:)]";
            case "EMOJI_SAD":         return "emoji @[:(]";
            case "EMOJI_SERIOUS":     return "emoji @[:|]";
            case "EMOJI_HEART":       return "emoji @[<3]";
            // --- Colores ---
            case "COLOR_NAME":        return "color (RED, BLUE, GREEN...)";
            case "COLOR_HEX":         return "color hexadecimal (#RRGGBB)";
            // --- Fin de archivo ---
            case "EOF":               return "fin de archivo";
            default:                  return token;
        }
    }


